// Memento — an opaque snapshot of the editor's state
class EditorMemento {
  #content;
  #cursor;

  constructor(content, cursor) {
    this.#content = content;
    this.#cursor = cursor;
  }

  // Only the originator uses these accessors
  getContent() { return this.#content; }
  getCursor()  { return this.#cursor; }
}

// Originator
class Editor {
  #content = '';
  #cursor = 0;

  type(text) {
    this.#content += text;
    this.#cursor = this.#content.length;
  }

  getContent() { return this.#content; }

  save() {
    return new EditorMemento(this.#content, this.#cursor);
  }

  restore(memento) {
    this.#content = memento.getContent();
    this.#cursor = memento.getCursor();
  }
}

// Caretaker — keeps the undo history
class History {
  #mementos = [];

  push(memento) { this.#mementos.push(memento); }
  pop()         { return this.#mementos.pop(); }
}

// Usage
const editor = new Editor();
const history = new History();

editor.type('Hello');
history.push(editor.save());

editor.type(', world');
console.log(editor.getContent()); // Hello, world

editor.restore(history.pop());
console.log(editor.getContent()); // Hello

