from __future__ import annotations
from dataclasses import dataclass


# Memento — an immutable snapshot of the editor's state
@dataclass(frozen=True)
class EditorMemento:
    content: str
    cursor: int


# Originator
class Editor:
    def __init__(self) -> None:
        self._content = ''
        self._cursor = 0

    def type(self, text: str) -> None:
        self._content += text
        self._cursor = len(self._content)

    def get_content(self) -> str:
        return self._content

    def save(self) -> EditorMemento:
        return EditorMemento(self._content, self._cursor)

    def restore(self, memento: EditorMemento) -> None:
        self._content = memento.content
        self._cursor = memento.cursor


# Caretaker — keeps the undo history
class History:
    def __init__(self) -> None:
        self._mementos: list[EditorMemento] = []

    def push(self, memento: EditorMemento) -> None:
        self._mementos.append(memento)

    def pop(self) -> EditorMemento | None:
        return self._mementos.pop() if self._mementos else None


# Usage
editor = Editor()
history = History()

editor.type('Hello')
history.push(editor.save())

editor.type(', world')
print(editor.get_content())  # Hello, world

snapshot = history.pop()
if snapshot:
    editor.restore(snapshot)
print(editor.get_content())  # Hello
